/**
 * QR Code Generator - Minimal implementation
 * Based on the QR code specification (ISO/IEC 18004)
 * Supports versions 1-10 with error correction level M
 */
const QRCode = (function () {
    'use strict';

    // Error correction level M codewords & blocks per version
    const EC_PARAMS = [
        null,
        { totalCW: 26, ecCW: 10, blocks: 1 },   // v1
        { totalCW: 44, ecCW: 16, blocks: 1 },   // v2
        { totalCW: 70, ecCW: 26, blocks: 1 },   // v3
        { totalCW: 100, ecCW: 18, blocks: 2 },  // v4
        { totalCW: 134, ecCW: 24, blocks: 2 },  // v5
        { totalCW: 172, ecCW: 16, blocks: 4 },  // v6
        { totalCW: 196, ecCW: 18, blocks: 4 },  // v7
        { totalCW: 242, ecCW: 24, blocks: 4 },  // v8 (2 groups)
        { totalCW: 292, ecCW: 30, blocks: 4 },  // v9 (2 groups)
        { totalCW: 346, ecCW: 18, blocks: 6 },  // v10 (2 groups, but we simplify)
    ];

    // Number of data codewords for ECL M per version
    const DATA_CODEWORDS = [
        null, 16, 28, 44, 64, 86, 108, 124, 154, 182, 216
    ];

    // Alignment pattern positions per version
    const ALIGNMENT_POSITIONS = [
        null, [], [6, 18], [6, 22], [6, 26], [6, 30],
        [6, 34], [6, 22, 38], [6, 24, 42], [6, 26, 46], [6, 28, 50]
    ];

    // GF(256) math for Reed-Solomon
    const GF_EXP = new Uint8Array(512);
    const GF_LOG = new Uint8Array(256);

    (function initGF() {
        let x = 1;
        for (let i = 0; i < 255; i++) {
            GF_EXP[i] = x;
            GF_LOG[x] = i;
            x <<= 1;
            if (x >= 256) x ^= 0x11d;
        }
        for (let i = 255; i < 512; i++) {
            GF_EXP[i] = GF_EXP[i - 255];
        }
    })();

    function gfMul(a, b) {
        if (a === 0 || b === 0) return 0;
        return GF_EXP[GF_LOG[a] + GF_LOG[b]];
    }

    function rsGeneratorPoly(nsym) {
        let g = [1];
        for (let i = 0; i < nsym; i++) {
            const newG = new Array(g.length + 1).fill(0);
            for (let j = 0; j < g.length; j++) {
                newG[j] ^= g[j];
                newG[j + 1] ^= gfMul(g[j], GF_EXP[i]);
            }
            g = newG;
        }
        return g;
    }

    function rsEncode(data, nsym) {
        const gen = rsGeneratorPoly(nsym);
        const res = new Uint8Array(data.length + nsym);
        res.set(data);
        for (let i = 0; i < data.length; i++) {
            const coef = res[i];
            if (coef !== 0) {
                for (let j = 0; j < gen.length; j++) {
                    res[i + j] ^= gfMul(gen[j], coef);
                }
            }
        }
        return new Uint8Array(res.buffer, data.length, nsym);
    }

    // Encode text as byte-mode data
    function encodeData(text, version) {
        const maxDataCW = DATA_CODEWORDS[version];
        const bytes = new TextEncoder().encode(text);
        const bits = [];

        // Mode indicator: byte mode = 0100
        bits.push(0, 1, 0, 0);

        // Character count indicator
        const ccBits = version <= 9 ? 8 : 16;
        for (let i = ccBits - 1; i >= 0; i--) {
            bits.push((bytes.length >> i) & 1);
        }

        // Data
        for (const b of bytes) {
            for (let i = 7; i >= 0; i--) {
                bits.push((b >> i) & 1);
            }
        }

        // Terminator (up to 4 bits)
        const maxBits = maxDataCW * 8;
        for (let i = 0; i < 4 && bits.length < maxBits; i++) {
            bits.push(0);
        }

        // Pad to byte boundary
        while (bits.length % 8 !== 0 && bits.length < maxBits) {
            bits.push(0);
        }

        // Pad codewords
        const pads = [0xec, 0x11];
        let padIdx = 0;
        while (bits.length < maxBits) {
            for (let i = 7; i >= 0; i--) {
                bits.push((pads[padIdx] >> i) & 1);
            }
            padIdx ^= 1;
        }

        // Convert to bytes
        const codewords = new Uint8Array(maxDataCW);
        for (let i = 0; i < maxDataCW; i++) {
            let val = 0;
            for (let j = 0; j < 8; j++) {
                val = (val << 1) | (bits[i * 8 + j] || 0);
            }
            codewords[i] = val;
        }

        return codewords;
    }

    function getMinVersion(text) {
        const byteLen = new TextEncoder().encode(text).length;
        for (let v = 1; v <= 10; v++) {
            const overhead = v <= 9 ? 2 : 3; // mode(0.5) + count(1 or 2) rounded
            if (byteLen + overhead <= DATA_CODEWORDS[v]) return v;
        }
        return 10; // max supported
    }

    // Build the QR matrix
    function generate(text) {
        const version = getMinVersion(text);
        const size = 17 + version * 4;
        const matrix = Array.from({ length: size }, () => new Int8Array(size)); // 0=empty, 1=black, -1=white(reserved)
        const reserved = Array.from({ length: size }, () => new Uint8Array(size)); // 1=reserved

        function setModule(row, col, val, isReserved = true) {
            if (row >= 0 && row < size && col >= 0 && col < size) {
                matrix[row][col] = val ? 1 : -1;
                if (isReserved) reserved[row][col] = 1;
            }
        }

        // Finder patterns
        function drawFinder(row, col) {
            for (let dr = -1; dr <= 7; dr++) {
                for (let dc = -1; dc <= 7; dc++) {
                    const r = row + dr, c = col + dc;
                    if (r < 0 || r >= size || c < 0 || c >= size) continue;
                    const isBlack = (dr >= 0 && dr <= 6 && (dc === 0 || dc === 6)) ||
                        (dc >= 0 && dc <= 6 && (dr === 0 || dr === 6)) ||
                        (dr >= 2 && dr <= 4 && dc >= 2 && dc <= 4);
                    const isWhite = (dr === -1 || dr === 7 || dc === -1 || dc === 7);
                    if (isBlack) setModule(r, c, true);
                    else if (isWhite || (dr >= 0 && dr <= 6 && dc >= 0 && dc <= 6)) setModule(r, c, false);
                }
            }
        }

        drawFinder(0, 0);
        drawFinder(0, size - 7);
        drawFinder(size - 7, 0);

        // Timing patterns
        for (let i = 8; i < size - 8; i++) {
            setModule(6, i, i % 2 === 0);
            setModule(i, 6, i % 2 === 0);
        }

        // Alignment patterns
        const alignPos = ALIGNMENT_POSITIONS[version];
        if (alignPos.length > 0) {
            for (const r of alignPos) {
                for (const c of alignPos) {
                    // Skip if overlapping finder
                    if (r <= 8 && c <= 8) continue;
                    if (r <= 8 && c >= size - 8) continue;
                    if (r >= size - 8 && c <= 8) continue;
                    for (let dr = -2; dr <= 2; dr++) {
                        for (let dc = -2; dc <= 2; dc++) {
                            const isBlack = Math.abs(dr) === 2 || Math.abs(dc) === 2 ||
                                (dr === 0 && dc === 0);
                            setModule(r + dr, c + dc, isBlack);
                        }
                    }
                }
            }
        }

        // Dark module
        setModule(size - 8, 8, true);

        // Reserve format info areas
        for (let i = 0; i < 8; i++) {
            if (!reserved[8][i]) { reserved[8][i] = 1; matrix[8][i] = 0; }
            if (!reserved[8][size - 1 - i]) { reserved[8][size - 1 - i] = 1; matrix[8][size - 1 - i] = 0; }
            if (!reserved[i][8]) { reserved[i][8] = 1; matrix[i][8] = 0; }
            if (!reserved[size - 1 - i][8]) { reserved[size - 1 - i][8] = 1; matrix[size - 1 - i][8] = 0; }
        }
        reserved[8][8] = 1;

        // Reserve version info areas (v >= 7 only)
        if (version >= 7) {
            for (let i = 0; i < 6; i++) {
                for (let j = 0; j < 3; j++) {
                    reserved[i][size - 11 + j] = 1;
                    reserved[size - 11 + j][i] = 1;
                }
            }
        }

        // Encode data
        const dataCW = encodeData(text, version);
        const ecParams = EC_PARAMS[version];
        const ecCWPerBlock = ecParams.ecCW;
        const totalDataCW = DATA_CODEWORDS[version];
        const numBlocks = ecParams.blocks;
        const baseCWPerBlock = Math.floor(totalDataCW / numBlocks);
        const extraBlocks = totalDataCW % numBlocks;

        // Split data into blocks
        const dataBlocks = [];
        let offset = 0;
        for (let b = 0; b < numBlocks; b++) {
            const blockSize = baseCWPerBlock + (b >= numBlocks - extraBlocks && extraBlocks > 0 ? 1 : 0);
            dataBlocks.push(dataCW.slice(offset, offset + blockSize));
            offset += blockSize;
        }

        // Generate EC for each block
        const ecBlocks = dataBlocks.map(block => rsEncode(block, ecCWPerBlock));

        // Interleave data codewords
        const maxDataBlockLen = baseCWPerBlock + (extraBlocks > 0 ? 1 : 0);
        const interleaved = [];
        for (let i = 0; i < maxDataBlockLen; i++) {
            for (let b = 0; b < numBlocks; b++) {
                if (i < dataBlocks[b].length) {
                    interleaved.push(dataBlocks[b][i]);
                }
            }
        }
        // Interleave EC codewords
        for (let i = 0; i < ecCWPerBlock; i++) {
            for (let b = 0; b < numBlocks; b++) {
                interleaved.push(ecBlocks[b][i]);
            }
        }

        // Convert to bit stream
        const dataBits = [];
        for (const cw of interleaved) {
            for (let i = 7; i >= 0; i--) {
                dataBits.push((cw >> i) & 1);
            }
        }

        // Place data bits
        let bitIdx = 0;
        let upward = true;
        for (let col = size - 1; col >= 0; col -= 2) {
            if (col === 6) col = 5; // skip timing pattern column
            const rows = upward ?
                Array.from({ length: size }, (_, i) => size - 1 - i) :
                Array.from({ length: size }, (_, i) => i);
            for (const row of rows) {
                for (let dc = 0; dc <= 1; dc++) {
                    const c = col - dc;
                    if (c < 0 || c >= size) continue;
                    if (reserved[row][c]) continue;
                    if (bitIdx < dataBits.length) {
                        matrix[row][c] = dataBits[bitIdx] ? 1 : -1;
                    } else {
                        matrix[row][c] = -1;
                    }
                    bitIdx++;
                }
            }
            upward = !upward;
        }

        // Masking — try all 8 mask patterns, pick the best
        function getMaskFn(pattern) {
            switch (pattern) {
                case 0: return (r, c) => (r + c) % 2 === 0;
                case 1: return (r, c) => r % 2 === 0;
                case 2: return (r, c) => c % 3 === 0;
                case 3: return (r, c) => (r + c) % 3 === 0;
                case 4: return (r, c) => (Math.floor(r / 2) + Math.floor(c / 3)) % 2 === 0;
                case 5: return (r, c) => ((r * c) % 2 + (r * c) % 3) === 0;
                case 6: return (r, c) => ((r * c) % 2 + (r * c) % 3) % 2 === 0;
                case 7: return (r, c) => ((r + c) % 2 + (r * c) % 3) % 2 === 0;
            }
        }

        function applyMask(mat, maskFn) {
            const result = mat.map(row => new Int8Array(row));
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    if (!reserved[r][c] && maskFn(r, c)) {
                        result[r][c] = result[r][c] === 1 ? -1 : 1;
                    }
                }
            }
            return result;
        }

        function scoreMask(mat) {
            let penalty = 0;

            // Rule 1: consecutive same-colored modules in row/col
            for (let r = 0; r < size; r++) {
                let count = 1;
                for (let c = 1; c < size; c++) {
                    if ((mat[r][c] > 0) === (mat[r][c - 1] > 0)) {
                        count++;
                        if (count === 5) penalty += 3;
                        else if (count > 5) penalty += 1;
                    } else {
                        count = 1;
                    }
                }
            }
            for (let c = 0; c < size; c++) {
                let count = 1;
                for (let r = 1; r < size; r++) {
                    if ((mat[r][c] > 0) === (mat[r - 1][c] > 0)) {
                        count++;
                        if (count === 5) penalty += 3;
                        else if (count > 5) penalty += 1;
                    } else {
                        count = 1;
                    }
                }
            }

            // Rule 2: 2x2 blocks
            for (let r = 0; r < size - 1; r++) {
                for (let c = 0; c < size - 1; c++) {
                    const a = mat[r][c] > 0;
                    if (a === (mat[r][c + 1] > 0) &&
                        a === (mat[r + 1][c] > 0) &&
                        a === (mat[r + 1][c + 1] > 0)) {
                        penalty += 3;
                    }
                }
            }

            return penalty;
        }

        // Format info for ECL M (01)
        const FORMAT_POLY = 0x537;
        const FORMAT_MASK_PATTERN = 0x5412;

        function getFormatBits(maskPattern) {
            let data = (0b01 << 3) | maskPattern; // ECL M = 01
            let bits = data << 10;
            // BCH encoding
            let divisor = FORMAT_POLY << 4;
            for (let i = 14; i >= 10; i--) {
                if (bits & (1 << i)) {
                    bits ^= (divisor >> (14 - i)) << (i - 10);
                    // recalculate
                    bits = (data << 10) | (bits & 0x3FF);
                }
            }
            bits = (data << 10) | bits;
            // Actually do proper BCH
            let remainder = data << 10;
            for (let i = 4; i >= 0; i--) {
                if (remainder & (1 << (i + 10))) {
                    remainder ^= FORMAT_POLY << i;
                }
            }
            bits = (data << 10) | remainder;
            bits ^= FORMAT_MASK_PATTERN;
            return bits;
        }

        function placeFormatInfo(mat, maskPattern) {
            const bits = getFormatBits(maskPattern);
            // Around top-left finder
            const positions1 = [
                [8, 0], [8, 1], [8, 2], [8, 3], [8, 4], [8, 5], [8, 7], [8, 8],
                [7, 8], [5, 8], [4, 8], [3, 8], [2, 8], [1, 8], [0, 8]
            ];
            // Split between bottom-left and top-right
            const positions2 = [
                [size - 1, 8], [size - 2, 8], [size - 3, 8], [size - 4, 8],
                [size - 5, 8], [size - 6, 8], [size - 7, 8],
                [8, size - 8], [8, size - 7], [8, size - 6], [8, size - 5],
                [8, size - 4], [8, size - 3], [8, size - 2], [8, size - 1]
            ];

            for (let i = 0; i < 15; i++) {
                const bit = (bits >> i) & 1;
                const [r1, c1] = positions1[i];
                mat[r1][c1] = bit ? 1 : -1;
                const [r2, c2] = positions2[i];
                mat[r2][c2] = bit ? 1 : -1;
            }
        }

        let bestMask = 0;
        let bestScore = Infinity;
        let bestMatrix = null;

        for (let m = 0; m < 8; m++) {
            const masked = applyMask(matrix, getMaskFn(m));
            placeFormatInfo(masked, m);
            const score = scoreMask(masked);
            if (score < bestScore) {
                bestScore = score;
                bestMask = m;
                bestMatrix = masked;
            }
        }

        // Convert to boolean matrix (true = black)
        const result = [];
        for (let r = 0; r < size; r++) {
            const row = [];
            for (let c = 0; c < size; c++) {
                row.push(bestMatrix[r][c] > 0);
            }
            result.push(row);
        }

        return { matrix: result, size, version };
    }

    return { generate };
})();

if (typeof module !== 'undefined') module.exports = QRCode;
